def range_summary(nums):
    if not nums:
        return ''

    nums = sorted(set(nums))
    summary = []
    start, end = nums[0], nums[0]

    for num in nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start == end:
                summary.append(str(start))
            else:
                summary.append(f'{start}-{end}')
            start, end = num, num

    if start == end:
        summary.append(str(start))
    else:
        summary.append(f'{start}-{end}')

    return ', '.join(summary)
